828: Utility::GetLastAddressFromXffInfo Utility::getLastNonTrustedAddressFromXFF(
829:     const Http::RequestHeaderMap& request_headers,
830:     absl::Span<const Network::Address::CidrRange> trusted_cidrs) {
831:   const auto xff_header = request_headers.getForwardedForValue();
832:   static constexpr size_t MAX_ALLOWED_XFF_ENTRIES = 20;
833: 
834:   absl::InlinedVector<absl::string_view, 3> xff_entries = absl::StrSplit(xff_header, ',');
835:   // If there are more than 20 entries in the XFF header, refuse to parse.
836:   // There are very few valid use cases for this many entries and parsing too many has
837:   // a performance impact.
838:   if (xff_entries.size() > MAX_ALLOWED_XFF_ENTRIES) {
839:     ENVOY_LOG_MISC(trace, "Too many entries in x-forwarded-for header");
840:     return {nullptr, false};
841:   }
842: 
843:   Network::Address::InstanceConstSharedPtr last_valid_addr;
844: 
845:   for (auto it = xff_entries.rbegin(); it != xff_entries.rend(); it++) {
846:     const absl::string_view entry = StringUtil::trim(*it);
847:     auto addr = Network::Utility::parseInternetAddressNoThrow(std::string(entry));
848:     if (addr == nullptr) {
849:       return {nullptr, false};
850:     }
851:     last_valid_addr = addr;
852: 
853:     bool remote_address_is_trusted_proxy = false;
854:     for (const auto& cidr : trusted_cidrs) {
855:       if (cidr.isInRange(*addr.get())) {
856:         remote_address_is_trusted_proxy = true;
857:         break;
858:       }
859:     }
860: 
861:     if (remote_address_is_trusted_proxy) {
862:       continue;
863:     }
864: 
865:     // If we reach here we found a non-trusted address
866:     return {addr, xff_entries.size() == 1};
867:   }
868:   // If we reach this point all addresses in XFF were considered trusted, so return
869:   // first IP in XFF (the last in the reverse-evaluated chain).
870:   return {last_valid_addr, xff_entries.size() == 1};
871: }
