1388:                              absl::string_view body, bool dropped, absl::string_view details) {
1389:   // If we have not yet sent anything downstream, send a response with an appropriate status code.
1390:   // Otherwise just reset the ongoing response.
1391:   callbacks_->streamInfo().setResponseFlag(response_flags);
1392: 
1393:   // Check if buffer overflow occurred and override error details accordingly
